// ── ANNUAL INCOME REPORT ──────────────────────────────────────────
function generateAnnualReport(loads, trucks, year) {
  const yearLoads = loads.filter(l => l.date && l.date.startsWith(String(year)));
  const gross = yearLoads.reduce((s,l)=>s+l.rate,0);
  const totalDiesel = yearLoads.reduce((s,l)=>s+l.diesel,0);
  const dispatch10 = gross * 0.10;
  const driver30 = gross * 0.30;
  const insurance = 52 * 250; // weekly insurance * 52 weeks
  const net = gross - dispatch10 - driver30 - insurance - totalDiesel;

  // Per driver income
  const driverIncome = ["Carlos Mendez","John Williams","Maria Lopez","David Chen"].map(d=>{
    const dl = yearLoads.filter(l=>l.driver===d);
    const dg = dl.reduce((s,l)=>s+l.rate,0);
    return {name:d, role:"Driver", loads:dl.length, gross:dg, income:dg*0.30};
  });

  // Dispatch income (10% of gross)
  const dispatchIncome = ["Ana Martinez","Pedro Salinas","Kevin Torres"].map(d=>({
    name:d, role:"Dispatch", income:dispatch10/3, gross:gross
  }));

  // Maintenance costs from trucks
  const yearMx = trucks.flatMap(t=>
    (t.maintenances||[]).filter(m=>m.date&&m.date.startsWith(String(year)))
  );
  const totalMxCost = yearMx.reduce((s,m)=>s+(m.cost||0),0);

  return {yearLoads, gross, totalDiesel, dispatch10, driver30, insurance, net, driverIncome, dispatchIncome, totalMxCost, yearMx};
}

