// ── GPS TRACKING ─────────────────────────────────────────────────
// ── GEOFENCING ────────────────────────────────────────────────────
function checkGeofences(driverName, lat, lng, loads, setGeofenceAlerts) {
  const driverLoads = loads.filter(l=>l.driver===driverName&&l.deliveryDate);
  driverLoads.forEach(load=>{
    // Check if near delivery destination (within ~5 miles radius)
    if(load.deliveryLat && load.deliveryLng) {
      const dist = Math.sqrt(Math.pow(lat-load.deliveryLat,2)+Math.pow(lng-load.deliveryLng,2))*69;
      if(dist < 5) {
        const alert = {id:Date.now(),driver:driverName,type:"arrival",load,message:`${driverName} está llegando a ${load.to}`,time:new Date().toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"})};
        setGeofenceAlerts(prev=>{
          const exists = prev.find(a=>a.driver===driverName&&a.load?.id===load.id);
          return exists ? prev : [...prev.slice(-9), alert];
        });
        if("Notification" in window && Notification.permission==="granted") {
          new Notification("JFX Carrier - Llegada",{body:alert.message,icon:"/icons/icon-192.png"});
        }
      }
    }
  });
}

