function startTracking(driverName, truckUnit, setDriverLocations, setTrackingActive, setTrackingInterval) {
  if(!navigator.geolocation) { alert("Tu dispositivo no soporta GPS"); return; }
  setTrackingActive(true);
  // Get position immediately
  const updatePos = () => {
    navigator.geolocation.getCurrentPosition(pos=>{
      setDriverLocations(prev=>({
        ...prev,
        [driverName]:{
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
          accuracy: pos.coords.accuracy,
          timestamp: new Date().toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"}),
truck: truckUnit||"N/A",
          driver: driverName
        }
      }));
    }, err=>console.log("GPS error:",err), {enableHighAccuracy:true,timeout:10000});
  };
  updatePos();
  // Update every 30 seconds
  const interval = setInterval(updatePos, 30000);
  setTrackingInterval(interval);
}

function stopTracking(trackingInterval, setTrackingActive, setTrackingInterval) {
  if(trackingInterval) clearInterval(trackingInterval);
  setTrackingActive(false);
  setTrackingInterval(null);
}

function getWeekStart() {
  const now = new Date();
  const day = now.getDay();
  const daysSinceTue = (day + 5) % 7;
  const tue = new Date(now);
  tue.setDate(now.getDate() - daysSinceTue);
  return tue.toISOString().split("T")[0];
}
function getWeekEnd() {
  const start = new Date(getWeekStart());
  const end = new Date(start);
  end.setDate(start.getDate() + 6);
  return end.toISOString().split("T")[0];
}

